  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using the clues from the earlier lessons on Thai cuisine. Recall the balance of flavors in Thai dishes and the common ingredients associated with them.",
        "codeTemplate": "Thai cuisine is known for its unique balance of flavors: ___, ___, ___, and ___.",
        "options": [
          "Sweet",
          "Sour",
          "Salty",
          "Spicy"
        ],
        "correctAnswer": "Sweet,Sour,Salty,Spicy",
        "explanation": "These four flavors are essential for creating harmonious dishes in Thai cuisine."
      },
      {
        "instruction": "Use the knowledge from the learning cards to identify the common ingredient that provides a sour flavor in Thai dishes.",
        "codeTemplate": "The sour flavor in Thai cuisine is often derived from ___.",
        "options": [
          "lime juice",
          "coconut milk",
          "fish sauce",
          "palm sugar"
        ],
        "correctAnswer": "lime juice",
        "explanation": "Lime juice is a key ingredient that adds a sour flavor to many Thai dishes."
      }
    ]
  }
}
